(async () => {
  if (!game.user.isGM) { ui.notifications.warn("BR2 Campaign State: GM only."); return; }

  const FLAG_NS = "blooming-rot-2";
  const STATE_KEY = "campaign-state";
  const CLOCK_KEY = "phase-clocks";

  // Lazy-register both world-scoped settings on first run (Foundry v13 idiom).
  if (!game.settings.settings.has(FLAG_NS + "." + STATE_KEY)) {
    game.settings.register(FLAG_NS, STATE_KEY, { scope: "world", config: false, type: Object,
      default: { sereth: 3, closure: 3, pell: 6, quill: 3, lies: [] } });
  }
  if (!game.settings.settings.has(FLAG_NS + "." + CLOCK_KEY)) {
    game.settings.register(FLAG_NS, CLOCK_KEY, { scope: "world", config: false, type: Object,
      default: { phase: 1, trailClock: 0, heatClock: 0 } });
  }

  const serethOpts  = ["Indicted (Path A)", "Privately removed (Path B)", "Kinetically removed (Path C)", "Unresolved"];
  const closureOpts = ["Passed", "Held over", "Defeated", "Unresolved"];
  const pellOpts    = ["Exposed", "Turned", "Fed false information", "Shadowed", "Removed", "Killed", "Unresolved"];
  const quillOpts   = ["Captured", "Escaped", "Never reached", "Unresolved"];
  const lieList = [
    "Lie 1 \u2014 Haskur in Rel Astra",
    "Lie 2 \u2014 party pursuing wood correspondent",
    "Lie 3 \u2014 party has no usable Sereth evidence",
    "Lie 4 \u2014 party intends to expose Galenix Naelax",
    "Lie 5 \u2014 party returning to Hardby"
  ];

  const current = game.settings.get(FLAG_NS, STATE_KEY) ?? { sereth: 3, closure: 3, pell: 6, quill: 3, lies: [] };
  const clocks  = game.settings.get(FLAG_NS, CLOCK_KEY)  ?? { phase: 1, trailClock: 0, heatClock: 0 };

  // ---- helpers ----
  const mkSelect = (label, opts, cur, name) => {
    const options = opts.map((o, i) =>
      `<option value="${i}"${i === cur ? " selected" : ""}>${o}</option>`).join("");
    return `<div class="form-group">
      <label style="flex:0 0 120px;">${label}</label>
      <select name="${name}" style="flex:1;">${options}</select>
    </div>`;
  };

  const lieCBs = lieList.map((l, i) =>
    `<label style="display:flex;align-items:flex-start;gap:8px;cursor:pointer;margin:0 0 6px 0;font-size:0.9em;line-height:1.35;">
      <input type="checkbox" name="lie${i}" style="margin-top:2px;flex-shrink:0;"${current.lies.includes(i) ? " checked" : ""}/>
      <span>${l}</span>
    </label>`
  ).join("");

  // Link to the GM Macros reference page in the Welcome journal
  const JRNL_UUID = "Compendium.blooming-rot-2.welcome.JournalEntry.BR2WelcomeJrnl";
  const PAGE_ID   = "BR2WlPgMacros";
  const openRef   = `fromUuid('${JRNL_UUID}').then(d=>d&&d.sheet.render(true,{pageId:'${PAGE_ID}'}));return false;`;

  const html = `
<form style="display:flex;flex-direction:column;gap:0;padding:2px 0;">

  <div style="background:#f5eed8;border:1px solid #b89860;border-radius:4px;
              padding:8px 12px;margin-bottom:14px;font-size:0.82em;line-height:1.5;color:#3a2e1a;">
    <strong>How to use:</strong> Record the carry-forward state of major Phase&nbsp;2&ndash;5
    threads after each session where one resolves. Check any lies the party has
    <em>successfully planted</em> with the conspiracy (not merely said aloud &mdash;
    planted, so the network acted on it). <em>Save + Report</em> saves the state
    and whispers a summary to GM chat.
    <a href="#" style="display:block;margin-top:5px;"
       onclick="${openRef}">&#x2197; Full reference &mdash; GM Utility Macros (Welcome journal)</a>
  </div>

  <p style="font-weight:600;margin:0 0 6px 0;font-size:0.82em;text-transform:uppercase;
            letter-spacing:0.05em;color:#5a3e1b;border-bottom:1px solid #c4a96e;padding-bottom:3px;">Thread Status</p>

  ${mkSelect("Sereth",        serethOpts,  current.sereth,  "sereth")}
  ${mkSelect("Closure motion", closureOpts, current.closure, "closure")}
  ${mkSelect("Pell",           pellOpts,    current.pell,    "pell")}
  ${mkSelect("Vesten Quill",   quillOpts,   current.quill,   "quill")}

  <p style="font-weight:600;margin:14px 0 8px 0;font-size:0.82em;text-transform:uppercase;
            letter-spacing:0.05em;color:#5a3e1b;border-bottom:1px solid #c4a96e;padding-bottom:3px;">Active Lies Fed to the Conspiracy</p>

  <div style="padding:0 4px;">
    ${lieCBs}
  </div>

</form>`;

  new Dialog({
    title: "BR2 Campaign State Snapshot",
    content: html,
    buttons: {
      save: {
        label: "Save + Report",
        callback: async (htmlEl) => {
          const form = htmlEl[0].querySelector("form");
          const lies = lieList
            .map((_, i) => form.elements["lie" + i]?.checked ? i : null)
            .filter(i => i !== null);
          const next = {
            sereth:  Number(form.elements.sereth.value),
            closure: Number(form.elements.closure.value),
            pell:    Number(form.elements.pell.value),
            quill:   Number(form.elements.quill.value),
            lies
          };
          await game.settings.set(FLAG_NS, STATE_KEY, next);
          const lieReport = next.lies.length
            ? next.lies.map(i => `<li>${lieList[i]}</li>`).join("")
            : "<li><em>none</em></li>";
          ChatMessage.create({
            content: `<div style="border:1px solid #8a7a5e;padding:8px 12px;border-radius:4px;background:#f3ead9;">
              <h3 style="margin:0 0 6px 0;font-size:1em;">BR2 Campaign State \u2014 Phase ${clocks.phase}</h3>
              <p style="margin:2px 0;"><strong>Sereth:</strong> ${serethOpts[next.sereth]}</p>
              <p style="margin:2px 0;"><strong>Closure motion:</strong> ${closureOpts[next.closure]}</p>
              <p style="margin:2px 0;"><strong>Pell:</strong> ${pellOpts[next.pell]}</p>
              <p style="margin:2px 0;"><strong>Vesten Quill:</strong> ${quillOpts[next.quill]}</p>
              <p style="margin:8px 0 2px 0;"><strong>Active lies:</strong></p>
              <ul style="margin:2px 0 6px 16px;padding:0;">${lieReport}</ul>
              <p style="margin:6px 0 0 0;color:#6b5b3c;font-size:0.88em;">
                <strong>Trail Clock:</strong> ${clocks.trailClock}&thinsp;/&thinsp;6
                &ensp;&middot;&ensp;
                <strong>Heat Clock:</strong> ${clocks.heatClock}&thinsp;/&thinsp;6
              </p>
            </div>`,
            whisper: [game.user.id]
          });
        }
      },
      cancel: { label: "Cancel" }
    },
    default: "save"
  }, { width: 500 }).render(true);
})();
